#include <bits/stdc++.h>
using namespace std;
const int N=10005,M=505;
int n,m,dp[N][M],a[N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	memset(dp,128,sizeof(dp));
	dp[0][0]=0;
	for(int i=1;i<=n;i++)
	{
		for(int j=0;j<=m;j++)
		{
			if(i+j<=n)
			{
				dp[i+j][0]=max(dp[i+j][0],dp[i-1][j+1]);
			}
			if(j==0) dp[i][j]=max(dp[i][j],dp[i-1][0]);
			else dp[i][j]=max(dp[i][j],dp[i-1][j-1]+a[i]);
		}
	}
	cout<<dp[n][0];
	return 0;
}
